interface ChartData {
  date: string;
  revenue: number;
  orders: number;
}

interface DashboardStats {
  total_revenue: number;
  total_orders: number;
  total_users: number;
  total_tickets: number;
  total_movies: number;
  monthly_revenue: number;
  recent_orders: Array<{
    id: string;
    user_name: string;
    user_email: string;
    movie_title: string;
    final_amount: number;
    status: string;
    created_at: string;
  }>;
  chart_data: ChartData[];
}

function MiniRevenueChart({ data }: { data: ChartData[] }) {
  const [hoveredIdx, setHoveredIdx] = useState<number | null>(null);
  if (!data || data.length === 0) return null;

  const W = 280;
  const H = 110;
  const PAD = { top: 12, right: 10, bottom: 28, left: 8 };
  const chartW = W - PAD.left - PAD.right;
  const chartH = H - PAD.top - PAD.bottom;

  const maxRev = Math.max(...data.map((d) => d.revenue), 1);
  const days = ["CN", "T2", "T3", "T4", "T5", "T6", "T7"];

  const pts = data.map((d, i) => ({
    x: PAD.left + (i / (data.length - 1)) * chartW,
    y: PAD.top + chartH - (d.revenue / maxRev) * chartH,
    ...d,
    dayLabel: days[new Date(d.date).getDay()],
    isToday: i === data.length - 1,
  }));

  // Cubic bezier smooth path
  const smooth = (points: typeof pts) => {
    if (points.length < 2) return "";
    let d = `M ${points[0].x} ${points[0].y}`;
    for (let i = 1; i < points.length; i++) {
      const prev = points[i - 1];
      const curr = points[i];
      const cpx = (prev.x + curr.x) / 2;
      d += ` C ${cpx} ${prev.y}, ${cpx} ${curr.y}, ${curr.x} ${curr.y}`;
    }
    return d;
  };

  const linePath = smooth(pts);
  const areaPath =
    linePath +
    ` L ${pts[pts.length - 1].x} ${PAD.top + chartH} L ${pts[0].x} ${PAD.top + chartH} Z`;

  const hovered = hoveredIdx !== null ? pts[hoveredIdx] : null;

  return (
    <div className="relative select-none">
      <svg
        width="100%"
        viewBox={`0 0 ${W} ${H}`}
        className="overflow-visible"
        style={{ display: "block" }}
      >
        <defs>
          <linearGradient id="areaGrad" x1="0" y1="0" x2="0" y2="1">
            <stop
              offset="0%"
              stopColor="var(--chart-grad-start)"
              stopOpacity="0.35"
            />
            <stop
              offset="100%"
              stopColor="var(--chart-grad-start)"
              stopOpacity="0"
            />
          </linearGradient>
          <filter id="glow">
            <feGaussianBlur stdDeviation="2.5" result="blur" />
            <feMerge>
              <feMergeNode in="blur" />
              <feMergeNode in="SourceGraphic" />
            </feMerge>
          </filter>
          <linearGradient id="lineGrad" x1="0" y1="0" x2="1" y2="0">
            <stop offset="0%" stopColor="var(--primary)" stopOpacity="0.6" />
            <stop offset="100%" stopColor="var(--primary)" />
          </linearGradient>
        </defs>

        {/* Horizontal grid lines */}
        {[0.25, 0.5, 0.75, 1].map((t) => (
          <line
            key={t}
            x1={PAD.left}
            y1={PAD.top + chartH * (1 - t)}
            x2={PAD.left + chartW}
            y2={PAD.top + chartH * (1 - t)}
            stroke="var(--text-primary)"
            strokeOpacity="0.05"
            strokeDasharray="3 4"
          />
        ))}

        {/* Area fill */}
        <path d={areaPath} fill="url(#areaGrad)" />

        {/* Line */}
        <path
          d={linePath}
          fill="none"
          stroke="url(#lineGrad)"
          strokeWidth="2"
          strokeLinecap="round"
          strokeLinejoin="round"
          filter="url(#glow)"
        />

        {/* Hover vertical line */}
        {hovered && (
          <line
            x1={hovered.x}
            y1={PAD.top}
            x2={hovered.x}
            y2={PAD.top + chartH}
            stroke="white"
            strokeOpacity="0.15"
            strokeWidth="1"
            strokeDasharray="3 3"
          />
        )}

        {/* Dots */}
        {pts.map((pt, i) => (
          <g key={i}>
            {/* Invisible hit area */}
            <rect
              x={pt.x - 16}
              y={PAD.top}
              width={32}
              height={chartH}
              fill="transparent"
              style={{ cursor: "pointer" }}
              onMouseEnter={() => setHoveredIdx(i)}
              onMouseLeave={() => setHoveredIdx(null)}
            />
            {/* Dot */}
            {(pt.isToday || hoveredIdx === i) && (
              <>
                <circle
                  cx={pt.x}
                  cy={pt.y}
                  r={6}
                  fill="var(--primary)"
                  fillOpacity="0.2"
                />
                <circle
                  cx={pt.x}
                  cy={pt.y}
                  r={3.5}
                  fill="var(--primary)"
                  filter="url(#glow)"
                />
                <circle cx={pt.x} cy={pt.y} r={2} fill="var(--text-primary)" />
              </>
            )}
            {!pt.isToday && hoveredIdx !== i && (
              <circle
                cx={pt.x}
                cy={pt.y}
                r={2}
                fill="white"
                fillOpacity="0.2"
              />
            )}

            <text
              x={pt.x}
              y={H - 4}
              textAnchor="middle"
              fontSize="9"
              fill={pt.isToday ? "var(--primary)" : "var(--text-secondary)"}
              fontWeight={pt.isToday ? "600" : "400"}
              opacity={pt.isToday ? "1" : "0.5"}
            >
              {pt.dayLabel}
            </text>
          </g>
        ))}

        {/* Tooltip */}
        {hovered &&
          (() => {
            const tipW = 80;
            const tipH = 30;
            let tipX = hovered.x - tipW / 2;
            tipX = Math.max(PAD.left, Math.min(tipX, W - PAD.right - tipW));
            const tipY = hovered.y - tipH - 8;

            return (
              <g>
                <rect
                  x={tipX}
                  y={tipY}
                  width={tipW}
                  height={tipH}
                  rx="6"
                  fill="var(--bg-sidebar)"
                  stroke="var(--primary)"
                  strokeOpacity="0.4"
                  strokeWidth="0.8"
                />
                <text
                  x={tipX + tipW / 2}
                  y={tipY + 11}
                  textAnchor="middle"
                  fontSize="8"
                  fill="rgba(255,255,255,0.5)"
                >
                  {hovered.dayLabel}
                </text>
                <text
                  x={tipX + tipW / 2}
                  y={tipY + 23}
                  textAnchor="middle"
                  fontSize="9.5"
                  fill="white"
                  fontWeight="600"
                >
                  {formatRevShort(hovered.revenue)}─æ
                </text>
              </g>
            );
          })()}
      </svg>
    </div>
  );
}

function formatRevShort(amount: number) {
  if (amount >= 1_000_000) return `${(amount / 1_000_000).toFixed(1)}M`;
  if (amount >= 1_000) return `${(amount / 1_000).toFixed(0)}K`;
  return `${amount}`;
}

// --- Donut Chart ---
function DonutChart({
  data,
  colors,
}: {
  data: { label: string; value: number }[];
  colors: string[];
}) {
  const total = data.reduce((acc, curr) => acc + curr.value, 0);

  const getCoordinatesForPercent = (percent: number) => {
    const x = Math.cos(2 * Math.PI * percent - Math.PI / 2);
    const y = Math.sin(2 * Math.PI * percent - Math.PI / 2);
    return [x, y];
  };

  const dataWithPercents = useMemo(() => {
    let current = 0;
    return data.map((item) => {
      const percent = total > 0 ? item.value / total : 0;
      const start = current;
      current += percent;
      return { ...item, percent, start };
    });
  }, [data, total]);

  return (
    <div className="flex items-center gap-6">
      <div className="w-24 h-24 relative">
        <svg viewBox="-1 -1 2 2" style={{ transform: "rotate(-90deg)" }}>
          {dataWithPercents.map((item: { value: number; label: string; percent: number; start: number }, index: number) => {
            if (item.value === 0) return null;
            const { percent, start } = item;
            const [startX, startY] = getCoordinatesForPercent(start);

            // Handle when single item is 100%
            if (percent === 1) {
              return (
                <circle
                  key={index}
                  cx="0"
                  cy="0"
                  r="0.8"
                  fill="transparent"
                  stroke={colors[index]}
                  strokeWidth="0.4"
                />
              );
            }

            const [endX, endY] = getCoordinatesForPercent(start + percent);
            const largeArcFlag = percent > 0.5 ? 1 : 0;
            const pathData = [
              `M ${startX * 0.8} ${startY * 0.8}`, // Move
              `A 0.8 0.8 0 ${largeArcFlag} 1 ${endX * 0.8} ${endY * 0.8}`, // Arc
            ].join(" ");

            return (
              <path
                key={index}
                d={pathData}
                fill="none"
                stroke={colors[index % colors.length]}
                strokeWidth="0.4"
              />
            );
          })}
        </svg>
        <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
          <span className="text-white text-xs font-bold">{total}</span>
          <span className="text-white/40 text-[9px]">Tß╗òng</span>
        </div>
      </div>

      <div className="flex-1 space-y-2">
        {data.map((item, i) => (
          <div key={i} className="flex justify-between items-center">
            <div className="flex items-center gap-2">
              <span
                className="w-2.5 h-2.5 rounded-full"
                style={{ backgroundColor: colors[i % colors.length] }}
              />
              <span className="text-white/70 text-xs">{item.label}</span>
            </div>
            <span className="text-white font-medium text-xs">
              {item.value} ({((item.value / total) * 100 || 0).toFixed(1)}%)
            </span>
          </div>
        ))}
      </div>
    </div>
  );
}

